const item = $input.first();
const body = item.json.body ?? item.json;
const treatmentId = body.treatment_id;
if (!treatmentId) {
  throw new Error('treatment_id is required');
}

const backendBaseUrl = $env.BACKEND_BASE_URL;
if (!backendBaseUrl) {
  throw new Error('BACKEND_BASE_URL is required');
}

const treatment = await $helpers.httpRequest({ method: 'GET', url: `${backendBaseUrl}/api/treatments/${treatmentId}/json`, json: true });
const shotsResponse = await $helpers.httpRequest({ method: 'GET', url: `${backendBaseUrl}/api/treatments/${treatmentId}/shots`, json: true });
const sequencesResponse = await $helpers.httpRequest({ method: 'GET', url: `${backendBaseUrl}/api/treatments/${treatmentId}/sequences`, json: true });

const shots = shotsResponse.records ?? [];
if (shots.length < 9) {
  throw new Error(`Expected 9 shots for ${treatmentId}, found ${shots.length}`);
}

const missingImages = shots.filter((shot) => !shot.fields?.image_path);
if (missingImages.length) {
  return [{
    json: {
      ok: false,
      workflow: 'evaluate-treatment',
      treatment_id: treatmentId,
      message: 'Evaluation blocked: some shots do not have image_path yet',
      missing_shot_ids: missingImages.map((shot) => shot.fields?.shot_id ?? shot.id),
      sequence_count: sequencesResponse.records?.length ?? 0,
      ready_for_judge: false
    }
  }];
}

return [{
  json: {
    ok: true,
    workflow: 'evaluate-treatment',
    treatment_id: treatmentId,
    treatment_title: treatment.title,
    shot_count: shots.length,
    sequence_count: sequencesResponse.records?.length ?? 0,
    grid_candidates: (sequencesResponse.records ?? []).map((record) => record.fields?.grid_image_path).filter(Boolean),
    ready_for_judge: true,
    message: 'Inputs prepared for judge/evaluation workflow'
  }
}];
